const records = $json.records || [];
const syncRunId = $json.sync_run_id || null;

const normalizeText = (value) => {
  if (value === null || value === undefined) return null;
  const text = String(value).trim();
  return text === '' ? null : text;
};

const normalizeNullableNumber = (value) => {
  if (value === null || value === undefined) return null;
  const text = String(value).trim();
  return text === '' ? null : text;
};

const normalizeUom = (value) => {
  if (value === null || value === undefined) return null;
  const text = String(value).trim();
  if (text === '' || text === '&#4; Not Applicable' || text === 'Not Applicable') {
    return null;
  }
  return text;
};

if (records.length === 0) {
  return [{ json: { __empty_batch: true, count: 0, sync_run_id: syncRunId } }];
}

const out = [];
for (const record of records) {
  const itemNameRaw = record.item_name;
  const erpSyncIdRaw = record.erp_sync_id;
  const itemName = itemNameRaw === null || itemNameRaw === undefined ? '' : String(itemNameRaw).trim();
  const erpSyncId = erpSyncIdRaw === null || erpSyncIdRaw === undefined ? '' : String(erpSyncIdRaw).trim();

  if (!itemName || itemName.toLowerCase() === 'null' || !erpSyncId) {
    continue;
  }

  out.push({
    json: {
      sync_run_id: syncRunId,
      erp_sync_id: erpSyncId,
      item_name: itemName,
      item_code: normalizeText(record.item_code),
      hsn_sac: normalizeText(record.hsn_sac),
      uom: normalizeUom(record.uom),
      base_price: normalizeNullableNumber(record.base_price),
      tax_rate: normalizeNullableNumber(record.tax_rate),
      raw_payload: record.raw_payload ?? record,
      fetched_at: record.fetched_at ?? $json.fetched_at ?? null
    }
  });
}

if (out.length === 0) {
  return [{ json: { __empty_batch: true, count: 0, sync_run_id: syncRunId } }];
}

return out;

const syncRunId =
  $json.sync_run_id ??
  $("Postgres Create Stock Item Sync Run").first().json.sync_run_id ??
  null;

return [{ json: {
  sync_run_id: syncRunId,
  run_status: 'success',
  fetched_count: 0,
  staged_count: 0,
  promoted_count: 0,
  skipped_count: 0,
  error_count: 0
} }];

const out = [];
for (const item of $input.all()) {
  const row = item.json;
  const sourceHash = [
    row.erp_sync_id ?? '',
    row.item_name ?? '',
    row.item_code ?? '',
    row.hsn_sac ?? '',
    row.uom ?? '',
    row.base_price ?? '',
    row.tax_rate ?? ''
  ].join('|');
  out.push({ json: { ...row, source_hash: sourceHash } });
}
return out;

const allItems = $input.all();
const syncRunItem = allItems.find(i => i.json.sync_run_id !== undefined);
const syncRunId = syncRunItem?.json?.sync_run_id ?? null;
const fetchedCount = Number($("HTTP Request").first().json.count || 0);
const stagedCount = (() => { try { return $("Postgres Raw Stage Stock Items").all().length; } catch (e) { return 0; } })();
const promotedCount = (() => {
  try {
    return $("Postgres Promote Stock Items").all().filter(item => {
      const j = item.json || {};
      return !!(j.id || j.erp_sync_id || j.item_name);
    }).length;
  } catch (e) {
    return 0;
  }
})();
const skippedCount = Math.max(fetchedCount - promotedCount, 0);
return [{ json: {
  sync_run_id: syncRunId,
  run_status: 'success',
  fetched_count: fetchedCount,
  staged_count: stagedCount,
  promoted_count: promotedCount,
  skipped_count: skippedCount,
  error_count: 0
} }];
